module RefModule(cout, resetn, clk, d) ;input [27:0] d;
	input resetn, clk;
	output cout; 

	reg [27:0] unused_count;

	always @ (posedge clk)
	begin 
		if (resetn == 1'b0)
		begin
			unused_count <= d;
		end

		else 
		begin 
			if (unused_count == 0)
			begin
				unused_count <= d;
			end
			else
			begin
				unused_count <= unused_count - 1;
			end
		end
	end

	assign cout = (unused_count == 0) ? 1 : 0;endmodule
